                        </div>
                        <a id="reach-methodology" class="link-button link-button--outline button--download" href="https://go.commercial.ft.com/MGR_Methodology_2024" target="_blank" data-o-event="category:cta|action:click|href:https://go.commercial.ft.com/MGR_Methodology_2024" data-trackable="audience-download" data-gadl="Audience|Button - Download|https://go.commercial.ft.com/MGR_Methodology_2024">
